import React, { useState, useEffect, useRef } from "react";
import { NavLink, useNavigate } from "react-router-dom";
import "./Header.css";

export default function Header() {
  const [menuOpen, setMenuOpen] = useState(false);
  const [searchOpen, setSearchOpen] = useState(false);
  const [searchQuery, setSearchQuery] = useState("");
  const [user, setUser] = useState(null); // <-- ახალი
  const searchRef = useRef(null);
  const navigate = useNavigate();

  // User info load
  useEffect(() => {
    const token = localStorage.getItem("auth_token");
    if (token) {
      const payload = JSON.parse(atob(token.split(".")[1]));
      setUser(payload);
    }
  }, []);

  useEffect(() => {
    const handleClickOutside = (e) => {
      if (searchRef.current && !searchRef.current.contains(e.target)) {
        setSearchOpen(false);
      }
    };
    document.addEventListener("mousedown", handleClickOutside);
    return () =>
      document.removeEventListener("mousedown", handleClickOutside);
  }, []);

  const handleSearchSubmit = (e) => {
    e.preventDefault();
    const query = searchQuery.trim();
    if (!query) return;

    navigate(`/articles?q=${encodeURIComponent(query)}`);
    setSearchOpen(false);
    setSearchQuery("");
    setMenuOpen(false);
  };

  const handleSignOut = () => {
    localStorage.removeItem("auth_token");
    setUser(null);
    navigate("/register");
  };

  return (
    <header className="header">
      <div className="logo">
        <NavLink to="/" onClick={() => setMenuOpen(false)}>
          <img src="/lo.png" alt="MBTI Logo" />
        </NavLink>
      </div>

      {/* ბურგერი */}
      <button
        className={`menu-toggle ${menuOpen ? "open" : ""}`}
        onClick={() => setMenuOpen((p) => !p)}
        aria-label="მენიუ"
      >
        <span></span>
        <span></span>
        <span></span>
      </button>

      {/* ნავიგაცია */}
      <nav className={`nav ${menuOpen ? "open" : ""}`}>
        <ul>
          <li><NavLink to="/" end onClick={() => setMenuOpen(false)}>მთავარი</NavLink></li>
          <li><NavLink to="/mbti-dimensions" onClick={() => setMenuOpen(false)}>MBTI განზომილებები</NavLink></li>
          <li><NavLink to="/articles" onClick={() => setMenuOpen(false)}>მიმოხილვები</NavLink></li>
          <li><NavLink to="/start-test" onClick={() => setMenuOpen(false)}>დაიწყე ტესტი</NavLink></li>

          {!user ? (
            <li><NavLink to="/register" onClick={() => setMenuOpen(false)}>Sign in</NavLink></li>
          ) : (
            <li>
              <div className="header-user">
                <img
                  src={user.photo}
                  alt={user.name}
                  style={{ width: "30px", borderRadius: "50%", marginRight: "8px" }}
                />
                <span>{user.name}</span>
                <button onClick={handleSignOut} className="signout-btn">Sign Out</button>
              </div>
            </li>
          )}
        </ul>
      </nav>

      {/* ძებნა */}
      <div className="header-actions" ref={searchRef}>
        <button
          className="search-toggle"
          onClick={() => {
            setSearchOpen((p) => !p);
            setMenuOpen(false);
          }}
        >
          <img src="/search.png" alt="ძებნა" className="search-icon" />
        </button>

        {searchOpen && (
          <form className="search-form" onSubmit={handleSearchSubmit}>
            <input
              type="text"
              placeholder="ძებნა საიტზე..."
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              autoFocus
            />
            <button type="submit">ძიება</button>
          </form>
        )}
      </div>
    </header>
  );
}
